#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char s[N + 1];
        memset(s, '(', N / 2);
        memset(s + N / 2, ')', N - N / 2);
        s[N] = '\0';
        for (int i = 0; i < K; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            // Try to construct a balanced string for the query (x, y)
            int balance = 0;
            for (int j = x; j <= y; j++) {
                if (s[j] == '(') balance++;
                else balance--;
                if (balance < 0) {
                    // If the string is not balanced, try to fix it
                    s[j] = '(';
                    balance++;
                }
            }
        }
        printf("%s\n", s);
    }
    return 0;
}

